-- 003_n5_words_inari
-- N5 單字匯入：伏見稻荷大社（前 100 字，あ-お 開頭）
-- 資料源：stephenmk/yomitan-jlpt-vocab (CC-BY, Jonathan Waller / Tanos)
-- 中文翻譯：Claude（學生友善口語風格）
-- 注意：scripts/import-n5.py 可重複再跑來補 meiji 等其他神社的字

with new_words as (
  returning id, lemma
)
select
  (select id from shrines where slug = 'inari'),
  nw.id,
  row_number() over (order by nw.lemma)
from new_words nw;
